// ---- GitHub → Automa Import ----
// Converts a GitHub blob URL to a raw URL, fetches the JSON,
// validates it as an Automa workflow, and triggers a file download.

(function () {
  var url = location.href;

  // Convert: github.com/user/repo/blob/branch/path → raw.githubusercontent.com/user/repo/branch/path
  var rawUrl = url;
  var blobMatch = url.match(/^https:\/\/github\.com\/([^/]+\/[^/]+)\/blob\/(.+)$/);
  if (blobMatch) {
    rawUrl = 'https://raw.githubusercontent.com/' + blobMatch[1] + '/' + blobMatch[2];
  }

  if (!rawUrl.match(/\.json(\?.*)?$/i)) {
    alert(
      '[Automa Import] This page does not appear to be a JSON file.\n\n' +
      'Please run this workflow while viewing a GitHub page for an Automa workflow JSON file.\n\n' +
      'Example URL:\n' +
      'https://github.com/kotaoue/helloAutoma/blob/<branch>/workflows/<name>.json'
    );
    automaNextBlock({ data: 'Error: not a JSON page' });
    return;
  }

  fetch(rawUrl)
    .then(function (res) {
      if (!res.ok) throw new Error('HTTP ' + res.status + ' – ' + res.statusText);
      return res.json();
    })
    .then(function (data) {
      if (!data.name || !data.drawflow) {
        throw new Error(
          'The JSON at this URL does not look like an Automa workflow ' +
          '(missing required fields: name, drawflow).'
        );
      }

      // Build a safe filename from the workflow name
      var filename =
        data.name
          .replace(/[^a-z0-9\-_. ]/gi, '-')
          .replace(/\s+/g, '-')
          .replace(/-+/g, '-')
          .replace(/^-|-$/g, '')
          .toLowerCase() + '.json';

      // Trigger browser file download
      var blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
      var blobUrl = URL.createObjectURL(blob);
      var a = document.createElement('a');
      a.href = blobUrl;
      a.download = filename;
      document.body.appendChild(a);
      a.click();
      setTimeout(function () {
        URL.revokeObjectURL(blobUrl);
        if (a.parentNode) a.parentNode.removeChild(a);
      }, 1000);

      automaSetVariable('workflowName', data.name);
      automaSetVariable('filename', filename);

      alert(
        '[Automa Import]\n\n' +
        '"' + data.name + '" has been saved as:\n' +
        '  ' + filename + '\n\n' +
        'To finish importing into Automa:\n' +
        '  1. Click the Automa extension icon\n' +
        '  2. Open Dashboard\n' +
        '  3. Click the import button (⭳) in the toolbar\n' +
        '  4. Select the downloaded file'
      );

      automaNextBlock({ data: 'Downloaded: ' + filename });
    })
    .catch(function (err) {
      alert('[Automa Import] Error: ' + err.message);
      automaNextBlock({ data: 'Error: ' + err.message });
    });
})();
